  pub fn split_vertical(&mut self, target: PaneId, new_pane: PaneId, ratio: f32);
  pub fn kill_pane(&mut self, target: PaneId);  // collapse parent Split if it had this leaf
  pub fn focus_direction(&self, current: PaneId, dir: Direction) -> Option<PaneId>;

Direction enum: Up, Down, Left, Right (maps onto split tree traversal).

Compute pane rectangles given window dims:
  pub fn pane_rects(&self, window_dims: (u16, u16)) -> HashMap<PaneId, Rect>;
  pub struct Rect { pub x: u16, pub y: u16, pub w: u16, pub h: u16 }

Proptest in tests/layout.rs:
