  - Loop:
      select! {
          chunk = reader.read(&mut buf) => terminal.vt_write(&buf[..chunk]),
          tick = interval.tick() => {
              let grid = pane.capture(&term)?;
              let ops = compute_diff(&prev, &grid);
              eprintln!("frame +{}ms ops={}", elapsed_ms, ops.len());
