Agent round-trip test (crates/phux-config/tests/agent_roundtrip.rs):
  use serde_json::json;
  let spec = json!({
      'general': { 'prefix': 'C-b', 'default_shell': '/bin/zsh' },
      'keybinds': [{ 'on': 'C-b c', 'action': 'new-window', 'args': [] }],
      'status': { 'enabled': true, 'widgets': [{ 'kind': 'time', 'format': '%H:%M' }] },
  });
  // 1. JSON → Config (via serde_json::from_value)
  let cfg: Config = serde_json::from_value(spec.clone())?;
  // 2. Config → TOML string (via toml::to_string_pretty)
  let toml_str = toml::to_string_pretty(&cfg)?;
  // 3. TOML string → Config (via nz4.1's parse_str)
  let reparsed = parse_str(&toml_str, Path::new('roundtrip'))?;
  // 4. JSON-equivalent representations match
  assert_eq!(serde_json::to_value(&cfg)?, serde_json::to_value(&reparsed)?);

This proves an agent CAN programmatically generate a valid phux.toml.

